import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { FiCheck, FiClock, FiX } from 'react-icons/fi';
import { bookingApi } from '../../api/bookingApi';
import BookingStatusBadge from './BookingStatusBadge';
import Modal from '../../components/common/Modal';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ErrorAlert from '../../components/common/ErrorAlert';
import BookingsTabs from './BookingsTabs';

const BookingApproval = () => {
  const navigate = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [reason, setReason] = useState('');
  const [action, setAction] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    loadPendingBookings();
  }, []);

  const loadPendingBookings = async () => {
    try {
      const data = await bookingApi.getAllBookings({ status: 'PENDING' });
      setBookings(data);
      setError(null);
    } catch (err) {
      setError('Failed to load pending bookings');
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = (booking) => {
    setSelectedBooking(booking);
    setAction('approve');
    setShowModal(true);
  };

  const handleReject = (booking) => {
    setSelectedBooking(booking);
    setAction('reject');
    setShowModal(true);
  };

  const handleSubmit = async () => {
    try {
      if (action === 'approve') {
        await bookingApi.approveBooking(selectedBooking.id, reason);
      } else {
        await bookingApi.rejectBooking(selectedBooking.id, reason);
      }
      setShowModal(false);
      setReason('');
      loadPendingBookings();
    } catch (err) {
      setError('Failed to process booking action');
    }
  };

  const handleDetails = (booking) => {
    navigate(`/bookings/${booking.id}`, { state: { booking } });
  };

  const formatDate = (dateString) =>
    new Date(dateString).toLocaleDateString(undefined, {
      month: 'short',
      day: '2-digit',
      year: 'numeric',
    });

  const formatTime = (dateString) =>
    new Date(dateString).toLocaleTimeString(undefined, {
      hour: '2-digit',
      minute: '2-digit',
    });

  if (loading) return <LoadingSpinner />;

  return (
    <div className="booking-approval-page">
      <div className="booking-page-header">
        <div>
          <h1>Request Management</h1>
          <p>Review and process pending room booking requests.</p>
        </div>
      </div>

      <BookingsTabs />

      {error && <ErrorAlert message={error} />}
      
      {bookings.length === 0 ? (
        <p className="no-data">No pending bookings to review.</p>
      ) : (
        <div className="booking-request-list">
          {bookings.map((booking) => (
            <article key={booking.id} className="booking-request-card">
              <div className="booking-request-top">
                <div className="booking-request-icon" aria-hidden="true">
                  <FiClock />
                </div>

                <div className="booking-request-main">
                  <div className="booking-request-meta">
                    <span className="booking-request-id">BK-{booking.id}</span>
                    <span className="booking-request-pill">{booking.status || 'PENDING'}</span>
                  </div>
                  <h3 className="booking-request-title">{booking.resourceName || 'Resource'}</h3>
                  <p className="booking-request-subtitle">
                    {booking.userName || 'Campus User'}
                    {booking.userRole ? ` • ${booking.userRole}` : ''}
                  </p>
                </div>

                <div className="booking-request-time">
                  <p className="booking-request-time-label">Timeframe</p>
                  <p className="booking-request-time-value">
                    {formatDate(booking.startTime)}, {formatTime(booking.startTime)} - {formatTime(booking.endTime)}
                  </p>
                </div>
              </div>

              <div className="booking-request-bottom">
                <div className="booking-request-message">
                  <span className="booking-request-message-icon" aria-hidden="true">
                    i
                  </span>
                  <p>{booking.purpose || 'No purpose provided.'}</p>
                </div>

                <div className="booking-request-actions">
                  <button
                    type="button"
                    className="booking-request-reject"
                    onClick={() => handleReject(booking)}
                  >
                    Reject
                  </button>
                  <button
                    type="button"
                    className="booking-request-accept"
                    onClick={() => handleApprove(booking)}
                  >
                    Accept Booking
                  </button>
                  <button
                    type="button"
                    className="booking-request-detail"
                    onClick={() => handleDetails(booking)}
                    aria-label="Details"
                  >
                    Details
                  </button>
                </div>
              </div>
            </article>
          ))}
        </div>
      )}

      <Modal
        isOpen={showModal}
        onClose={() => setShowModal(false)}
        title={action === 'approve' ? 'Approve Booking' : 'Reject Booking'}
      >
        <div className="modal-form">
          <p>
            Are you sure you want to {action} this booking for <strong>{selectedBooking?.resourceName}</strong>?
          </p>
          <div className="form-group">
            <label>Reason:</label>
            <textarea
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder={action === 'approve' ? 'Optional reason for approval...' : 'Required reason for rejection...'}
              rows="3"
            />
          </div>
          <div className="modal-actions">
            <button className="btn-cancel" onClick={() => setShowModal(false)}>
              Cancel
            </button>
            <button 
              className={action === 'approve' ? 'btn-approve' : 'btn-reject'}
              onClick={handleSubmit}
            >
              Confirm {action === 'approve' ? 'Approve' : 'Reject'}
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default BookingApproval;
